            // Idle mode names (ComboBox)
            { "ModeName0", "\u041F\u0440\u043E\u0441\u0442\u043E\u0439 \u2014 \u041F\u0430\u0440\u0430\u043B\u043B\u0435\u043B\u044C\u043D\u044B\u0439" },
            { "ModeName1", "\u041F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u2014 \u041F\u043E \u043E\u0434\u043D\u043E\u043C\u0443" },
