            // Idle mode descriptions (short)
            { "ModeDesc0", "\u0417\u0430\u043F\u0443\u0441\u043A \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u0438\u0433\u0440 \u043F\u0430\u0440\u0430\u043B\u043B\u0435\u043B\u044C\u043D\u043E \u043D\u0430 \u0437\u0430\u0434\u0430\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F.\nSteam \u0441\u0447\u0438\u0442\u0430\u0435\u0442 \u0447\u0430\u0441\u044B \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E (\u0434\u043E 32 \u0438\u0433\u0440).\n\u0421\u0430\u043C\u044B\u0439 \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u0440\u0435\u0436\u0438\u043C \u0434\u043B\u044F \u0431\u044B\u0441\u0442\u0440\u043E\u0433\u043E \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u044F \u0447\u0430\u0441\u043E\u0432." },
            { "ModeDesc1", "\u0418\u0433\u0440\u044B \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u0441\u0442\u0440\u043E\u0433\u043E \u043F\u043E \u043E\u0434\u043D\u043E\u0439.\n\u041A\u0430\u0436\u0434\u0430\u044F \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F, \u0437\u0430\u0442\u0435\u043C \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\n\u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0443\u044E \u0438\u0433\u0440\u0443 \u0432 \u0441\u043F\u0438\u0441\u043A\u0435." },
            { "ModeDesc2", "\u0426\u0438\u043A\u043B\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0440\u043E\u0442\u0430\u0446\u0438\u044F \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438.\n\u0413\u0440\u0443\u043F\u043F\u0430 \u0438\u0433\u0440 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F, \u0447\u0435\u0440\u0435\u0437 \u0437\u0430\u0434\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B\n\u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0430\u0435\u0442\u0441\u044F \u043D\u0430 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0443\u044E, \u0446\u0438\u043A\u043B\u0438\u0447\u043D\u043E \u043F\u0440\u043E\u0445\u043E\u0434\u044F \u0432\u0441\u0435.\n\u0418\u0434\u0435\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u043A\u0440\u0443\u0442\u043A\u0438 \u0441\u043E\u0442\u0435\u043D \u0438\u0433\u0440 \u0437\u0430 \u043E\u0434\u043D\u0443 \u0441\u0435\u0441\u0441\u0438\u044E." },
            { "ModeDesc3", "\u041D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u0435 \u0446\u0435\u043B\u0435\u0432\u044B\u0445 \u0447\u0430\u0441\u043E\u0432 \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438 (\u0434\u043E 32 \u0438\u0433\u0440 \u0437\u0430 \u0440\u0430\u0437).\n\u041A\u043E\u0433\u0434\u0430 \u0442\u0435\u043A\u0443\u0449\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0446\u0435\u043B\u0435\u0432\u043E\u0433\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438,\n\u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430.\n\u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u043A\u0430 \u0432\u0441\u0435 \u0438\u0433\u0440\u044B \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 \u0446\u0435\u043B\u0435\u0432\u044B\u0445 \u0447\u0430\u0441\u043E\u0432." },
            { "ModeDesc4", "Idle \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u043C \u043E\u043A\u043D\u0435.\n\u0418\u0433\u0440\u044B \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u0438 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u043F\u043E \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044E\n(\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0442\u043E\u043B\u044C\u043A\u043E \u043D\u043E\u0447\u044C\u044E \u0441 23:00 \u0434\u043E 07:00)." },
            { "ModeDesc5", "\u041F\u0435\u0440\u0438\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u0434\u043B\u044F \u043E\u0431\u0445\u043E\u0434\u0430 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0435\u043D\u0438\u044F.\n\u041A\u0430\u0436\u0434\u044B\u0435 N \u043C\u0438\u043D\u0443\u0442 \u0432\u0441\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0443\u0431\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0438\n\u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F, \u0438\u043C\u0438\u0442\u0438\u0440\u0443\u044F \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435." },

            // Idle mode detailed info
            { "DetailedInfo0", "\U0001F3AE \u041F\u0440\u043E\u0441\u0442\u043E\u0439 \u2014 \u041F\u0430\u0440\u0430\u043B\u043B\u0435\u043B\u044C\u043D\u044B\u0439 idle\n\n\u0421\u0430\u043C\u044B\u0439 \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u0440\u0435\u0436\u0438\u043C. \u0417\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442 \u0432\u044B\u0431\u0440\u0430\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0438\u0433\u0440\n\u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E. Steam \u0432\u0438\u0434\u0438\u0442 \u0438\u0445 \u043A\u0430\u043A \u0437\u0430\u043F\u0443\u0449\u0435\u043D\u043D\u044B\u0435 \u0438 \u043D\u0430\u043A\u0430\u043F\u043B\u0438\u0432\u0430\u0435\u0442\n\u0438\u0433\u0440\u043E\u0432\u043E\u0435 \u0432\u0440\u0435\u043C\u044F \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0439 \u0438\u0437 \u043D\u0438\u0445.\n\n\u2022 \u041C\u0430\u043A\u0441\u0438\u043C\u0443\u043C 32 \u0438\u0433\u0440\u044B \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E (\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 Steam)\n\u2022 \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435 \u043B\u0438\u043C\u0438\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0438\u043B\u0438 \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0442\u0435 \u0431\u0435\u0441\u0441\u0440\u043E\u0447\u043D\u043E\n\u2022 \u0412\u0441\u0435 \u0438\u0433\u0440\u044B \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F \u0438 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0432\u043C\u0435\u0441\u0442\u0435\n\n\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0431\u044B\u0441\u0442\u0440\u043E\u0433\u043E \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u044F \u0447\u0430\u0441\u043E\u0432 \u0432 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u0438\u0433\u0440\u0430\u0445." },
            { "DetailedInfo1", "\U0001F4CB \u041F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0439 \u2014 \u041F\u043E \u043E\u0434\u043D\u043E\u043C\u0443\n\n\u0417\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442 \u0438\u0433\u0440\u044B \u0441\u0442\u0440\u043E\u0433\u043E \u043F\u043E \u043E\u0434\u043D\u043E\u0439. \u041A\u043E\u0433\u0434\u0430 \u043E\u0434\u043D\u0430 \u0438\u0433\u0440\u0430\n\u043F\u0440\u043E\u0440\u0430\u0431\u043E\u0442\u0430\u043B\u0430 \u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F, \u043E\u043D\u0430 \u0437\u0430\u043A\u0440\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0438\n\u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0430\u044F \u0438\u0437 \u0441\u043F\u0438\u0441\u043A\u0430.\n\n\u2022 \u041E\u0434\u043D\u0430 \u0438\u0433\u0440\u0430 \u0437\u0430 \u0440\u0430\u0437\n\u2022 \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435 \u0447\u0430\u0441\u044B \u043D\u0430 \u0438\u0433\u0440\u0443\n\u2022 \u041E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0432\u0435\u0441\u044C \u0441\u043F\u0438\u0441\u043E\u043A \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0430\u0435\u043C\u044B\u0445 \u0438\u0433\u0440\n\n\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u043A\u043E\u0433\u0434\u0430 \u043D\u0443\u0436\u043D\u043E \u043D\u0430\u043A\u043E\u043F\u0438\u0442\u044C \u043C\u043D\u043E\u0433\u043E \u0447\u0430\u0441\u043E\u0432\n\u0432 \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u0445 \u0438\u0433\u0440\u0430\u0445 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E." },
            { "DetailedInfo2", "\U0001F504 \u0420\u043E\u0442\u0430\u0446\u0438\u044F \u2014 \u041F\u043E \u043A\u0440\u0443\u0433\u0443\n\n\u0426\u0438\u043A\u043B\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0440\u043E\u0442\u0430\u0446\u0438\u044F \u0433\u0440\u0443\u043F\u043F\u0430\u043C\u0438. \u041F\u0435\u0440\u0432\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u0438\u0433\u0440\n(\u0434\u043E 32) \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F, \u0447\u0435\u0440\u0435\u0437 \u0437\u0430\u0434\u0430\u043D\u043D\u044B\u0439 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F\n\u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0430\u044F. \u041A\u043E\u0433\u0434\u0430 \u0432\u0441\u0435 \u0433\u0440\u0443\u043F\u043F\u044B \u043F\u0440\u043E\u0439\u0434\u0435\u043D\u044B,\n\u0446\u0438\u043A\u043B \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0437\u0430\u043D\u043E\u0432\u043E.\n\n\u2022 \u0418\u043D\u0442\u0435\u0440\u0432\u0430\u043B \u0440\u043E\u0442\u0430\u0446\u0438\u0438 \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0441\u044F (5-1440 \u043C\u0438\u043D)\n\u2022 \u041A\u0430\u0436\u0434\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u2014 \u0434\u043E 32 \u0438\u0433\u0440\n\u2022 \u0420\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0431\u0435\u0441\u0441\u0440\u043E\u0447\u043D\u043E \u0438\u043B\u0438 \u0437\u0430\u0434\u0430\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F\n\n\u0418\u0434\u0435\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u043F\u0440\u043E\u043A\u0440\u0443\u0442\u043A\u0438 \u0441\u043E\u0442\u0435\u043D \u0438\u0433\u0440 \u0437\u0430 \u043E\u0434\u043D\u0443 \u0441\u0435\u0441\u0441\u0438\u044E,\n\u0440\u0430\u0441\u043F\u0440\u0435\u0434\u0435\u043B\u044F\u044F \u0447\u0430\u0441\u044B \u0440\u0430\u0432\u043D\u043E\u043C\u0435\u0440\u043D\u043E." },
            { "DetailedInfo3", "\U0001F3AF \u0426\u0435\u043B\u0435\u0432\u044B\u0435 \u0447\u0430\u0441\u044B \u2014 \u0414\u043E \u0446\u0435\u043B\u0438\n\n\u0417\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442 \u0433\u0440\u0443\u043F\u043F\u0443 \u0438\u0433\u0440 (\u0434\u043E 32 \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E) \u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442\n\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0447\u0430\u0441\u043E\u0432. \u041A\u043E\u0433\u0434\u0430 \u0432\u0440\u0435\u043C\u044F \u0438\u0441\u0442\u0435\u043A\u0430\u0435\u0442,\n\u0442\u0435\u043A\u0443\u0449\u0430\u044F \u0433\u0440\u0443\u043F\u043F\u0430 \u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0430\u044F.\n\u041F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u043A\u0430 \u0432\u0441\u0435 \u0438\u0433\u0440\u044B \u043D\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 \u0446\u0435\u043B\u0435\u0432\u044B\u0445 \u0447\u0430\u0441\u043E\u0432.\n\n\u2022 \u0413\u0440\u0443\u043F\u043F\u044B \u043F\u043E N \u0438\u0433\u0440 (\u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u043C\u0430\u043A\u0441\u0438\u043C\u0443\u043C 32)\n\u2022 \u0410\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u043F\u0435\u0440\u0435\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435 \u0433\u0440\u0443\u043F\u043F\n\u2022 \u041E\u0434\u043D\u043E\u043F\u0440\u043E\u0445\u043E\u0434\u043D\u044B\u0439: \u043A\u0430\u0436\u0434\u0430\u044F \u0438\u0433\u0440\u0430 \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u0434\u0438\u043D \u0440\u0430\u0437\n\n\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u043C\u0430\u0441\u0441\u043E\u0432\u043E\u0433\u043E \u043D\u0430\u043A\u043E\u043F\u043B\u0435\u043D\u0438\u044F \u0447\u0430\u0441\u043E\u0432 \u0432\u043E \u0432\u0441\u0435\u0445 \u0438\u0433\u0440\u0430\u0445." },
            { "DetailedInfo4", "\U0001F550 \u0420\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u0435 \u2014 \u0412\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435 \u043E\u043A\u043D\u043E\n\nIdle \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u043C \u043E\u043A\u043D\u0435.\n\u0412\u043D\u0435 \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043F\u0440\u0438\u043E\u0441\u0442\u0430\u043D\u0430\u0432\u043B\u0438\u0432\u0430\u044E\u0442\u0441\u044F,\n\u0438 \u0432\u043E\u0437\u043E\u0431\u043D\u043E\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043A\u043E\u0433\u0434\u0430 \u043E\u043A\u043D\u043E \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F.\n\n\u2022 \u0423\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435 \u0432\u0440\u0435\u043C\u044F \u043D\u0430\u0447\u0430\u043B\u0430 \u0438 \u043E\u043A\u043E\u043D\u0447\u0430\u043D\u0438\u044F (\u0427\u0427:\u041C\u041C)\n\u2022 \u041F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430 \u043D\u043E\u0447\u043D\u044B\u0445 \u043E\u043A\u043E\u043D (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, 23:00 \u2014 07:00)\n\u2022 \u041A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0438\u0433\u0440 \u0438 \u0447\u0430\u0441\u044B \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u044E\u0442\u0441\u044F\n\n\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0430\u0432\u0442\u043E\u043D\u043E\u043C\u043D\u043E\u0433\u043E idle (\u043D\u043E\u0447\u044C\u044E, \u043A\u043E\u0433\u0434\u0430 \u0432\u0430\u0441 \u043D\u0435\u0442 \u0437\u0430 \u041F\u041A)." },
            { "DetailedInfo5", "\U0001F6E1 \u0410\u043D\u0442\u0438-Idle \u2014 \u041E\u0431\u0445\u043E\u0434 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0435\u043D\u0438\u044F\n\n\u041F\u0435\u0440\u0438\u043E\u0434\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A \u0432\u0441\u0435\u0445 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432.\n\u041A\u0430\u0436\u0434\u044B\u0435 N \u043C\u0438\u043D\u0443\u0442 \u0432\u0441\u0435 idle-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0443\u0431\u0438\u0432\u0430\u044E\u0442\u0441\u044F\n\u0438 \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A\u0430\u044E\u0442\u0441\u044F. \u042D\u0442\u043E \u0438\u043C\u0438\u0442\u0438\u0440\u0443\u0435\u0442 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u043F\u043E\u0432\u0435\u0434\u0435\u043D\u0438\u0435\n(\u0437\u0430\u043F\u0443\u0441\u043A/\u0432\u044B\u0445\u043E\u0434 \u0438\u0437 \u0438\u0433\u0440).\n\n\u2022 \u0418\u043D\u0442\u0435\u0440\u0432\u0430\u043B \u043F\u0435\u0440\u0435\u0437\u0430\u043F\u0443\u0441\u043A\u0430 \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442\u0441\u044F (10-1440 \u043C\u0438\u043D)\n\u2022 \u0420\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0431\u0435\u0441\u0441\u0440\u043E\u0447\u043D\u043E \u0438\u043B\u0438 \u0437\u0430\u0434\u0430\u043D\u043D\u043E\u0435 \u0432\u0440\u0435\u043C\u044F\n\u2022 \u0421\u043E\u0437\u0434\u0430\u0435\u0442 \u0431\u043E\u043B\u0435\u0435 \u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043F\u0430\u0442\u0442\u0435\u0440\u043D \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438\n\n\u0420\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0434\u043B\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 idle-\u0441\u0435\u0441\u0441\u0438\u0439 (12+ \u0447\u0430\u0441\u043E\u0432)." },

